/// Generate TypeScript bindings for the editor's Tauri commands.
///
/// Writes a `bindings.ts` file to `output_path` using `tauri-specta`.
/// Only the commands with fully specta-compatible type signatures are exported
/// (`list_commands` and `run_command`). The generated file should be checked in
/// and kept up to date via `cargo xtask codegen`.
#[cfg(feature = "codegen")]
pub fn generate_bindings(output_path: &str) {
    use tauri_specta::{collect_commands, Builder};

    Builder::<tauri::Wry>::new()
        .commands(collect_commands![
            bridge::runner::list_commands,
            bridge::runner::run_command,
        ])
        .export(
            specta_typescript::Typescript::default()
                .header("// This file was generated by `cargo xtask codegen`. Do not edit manually.\n"),
            std::path::Path::new(output_path),
        )
        .expect("Failed to generate TypeScript bindings");
}

